package com.google.gson.internal.reflect;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;
import java.lang.reflect.InvocationHandler;
import java.lang.reflect.Method;
import java.lang.reflect.Proxy;

import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;

class ReflectionHelperTest {

  private static Object mockRecordHelper;
  private static Class<?> recordHelperClass;

  @BeforeAll
  static void setup() throws Exception {
    // Get the RecordHelper class via reflection
    recordHelperClass = Class.forName("com.google.gson.internal.reflect.ReflectionHelper$RecordHelper");

    // Create a dynamic proxy implementing RecordHelper interface
    mockRecordHelper = Proxy.newProxyInstance(
        recordHelperClass.getClassLoader(),
        new Class<?>[] {recordHelperClass},
        new InvocationHandler() {
          @Override
          public Object invoke(Object proxy, Method method, Object[] args) throws Throwable {
            if ("isRecord".equals(method.getName()) && args != null && args.length == 1) {
              Class<?> argClass = (Class<?>) args[0];
              // Default implementation returns false, overridden in tests by setting field again
              return false;
            }
            throw new UnsupportedOperationException("Method not mocked: " + method.getName());
          }
        });

    // Inject the proxy into ReflectionHelper.RECORD_HELPER
    Field recordHelperField = ReflectionHelper.class.getDeclaredField("RECORD_HELPER");
    recordHelperField.setAccessible(true);
    recordHelperField.set(null, mockRecordHelper);
  }

  @Test
  void testIsRecordTrue() throws Exception {
    // Create a new proxy that returns true for isRecord(String.class)
    Object proxy = Proxy.newProxyInstance(
        recordHelperClass.getClassLoader(),
        new Class<?>[] {recordHelperClass},
        (proxyObj, method, args) -> {
          if ("isRecord".equals(method.getName()) && args != null && args.length == 1) {
            Class<?> argClass = (Class<?>) args[0];
            return argClass == String.class;
          }
          throw new UnsupportedOperationException("Method not mocked: " + method.getName());
        });

    setRecordHelper(proxy);

    assertTrue(ReflectionHelper.isRecord(String.class));
    assertFalse(ReflectionHelper.isRecord(Integer.class));
  }

  @Test
  void testIsRecordFalse() throws Exception {
    // Create a new proxy that returns false for isRecord(Integer.class)
    Object proxy = Proxy.newProxyInstance(
        recordHelperClass.getClassLoader(),
        new Class<?>[] {recordHelperClass},
        (proxyObj, method, args) -> {
          if ("isRecord".equals(method.getName()) && args != null && args.length == 1) {
            Class<?> argClass = (Class<?>) args[0];
            return false;
          }
          throw new UnsupportedOperationException("Method not mocked: " + method.getName());
        });

    setRecordHelper(proxy);

    assertFalse(ReflectionHelper.isRecord(Integer.class));
    assertFalse(ReflectionHelper.isRecord(String.class));
  }

  private static void setRecordHelper(Object newHelper) throws Exception {
    Field recordHelperField = ReflectionHelper.class.getDeclaredField("RECORD_HELPER");
    recordHelperField.setAccessible(true);
    recordHelperField.set(null, newHelper);
  }
}
